echo '
<link href="https://unpkg.com/tabulator-tables@6.3.1/dist/css/tabulator.min.css" rel="stylesheet">
<script type="text/javascript" src="https://unpkg.com/tabulator-tables@6.3.1/dist/js/tabulator.min.js"></script>

<style>
/* =========================
   BARRA DE BOTONES A LA DERECHA
   ========================= */
.btn-tabulator-bar{
    margin-bottom: 14px;
    width: 100%;
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    align-items: center;
    

}

/* =========================
   BOTÓN BASE
   ========================= */
.btn-tabulator-bar button,
#btn-recargar,
#clear-filters,
#toggle-columns-btn,
#btn-seleccionados,
#btn-ejecutar-store-html,
#clear-sort{
    appearance: none;
    -webkit-appearance: none;
    border: 1px solid #cfd6e0;
    background: #ffffff;
    color: #1f3554;
    border-radius: 10px;
    padding: 10px 18px;
    min-height: 38px;
    font-size: 13px;
    font-weight: 600;
    line-height: 1;
    cursor: pointer;
    box-shadow: inset 0 1px 0 rgba(255,255,255,.85);
    transition: all .15s ease;
}

.btn-tabulator-bar button:hover,
#btn-recargar:hover,
#clear-filters:hover,
#toggle-columns-btn:hover,
#btn-seleccionados:hover,
#btn-ejecutar-store-html:hover,
#clear-sort:hover{
    transform: translateY(-1px);
    box-shadow: 0 3px 8px rgba(15, 23, 42, .10);
}

/* =========================
   BOTÓN AZUL
   ========================= */
#btn-recargar,
.btn-primary-tabulator{
    border-color: #2a5f91;
    background: linear-gradient(180deg, #3c78b2 0%, #2f679a 100%);
    color: #ffffff;
    box-shadow:
        inset 0 1px 0 rgba(255,255,255,.18),
        0 1px 2px rgba(0,0,0,.10);
}

#btn-recargar:hover,
.btn-primary-tabulator:hover{
    background: linear-gradient(180deg, #4685c2 0%, #346fa6 100%);
    border-color: #2b6296;
    color: #ffffff;
}

/* =========================
   BOTONES CLAROS
   ========================= */
#clear-filters,
#toggle-columns-btn,
#clear-sort,
.btn-light-tabulator{
    border-color: #cfd6e0;
    background: linear-gradient(180deg, #ffffff 0%, #f7f9fc 100%);
    color: #203654;
}

#clear-filters:hover,
#toggle-columns-btn:hover,
#clear-sort:hover,
.btn-light-tabulator:hover{
    border-color: #bcc8d8;
    background: linear-gradient(180deg, #ffffff 0%, #f1f5fa 100%);
    color: #1a3150;
}

/* =========================
   BOTÓN TURQUESA
   ========================= */
#btn-seleccionados,
.btn-accent-tabulator{
    border-color: #39a9c7;
    background: linear-gradient(180deg, #63c8e4 0%, #45b6d7 100%);
    color: #ffffff;
    box-shadow:
        inset 0 1px 0 rgba(255,255,255,.20),
        0 1px 2px rgba(0,0,0,.10);
}

#btn-seleccionados:hover,
.btn-accent-tabulator:hover{
    border-color: #2ea4c5;
    background: linear-gradient(180deg, #6fd0ea 0%, #4abfe0 100%);
    color: #ffffff;
}

/* =========================
   FOCUS
   ========================= */
.btn-tabulator-bar button:focus,
#btn-recargar:focus,
#clear-filters:focus,
#toggle-columns-btn:focus,
#btn-seleccionados:focus,
#btn-ejecutar-store-html:focus,
#clear-sort:focus{
    outline: none;
    box-shadow: 0 0 0 3px rgba(96, 165, 250, .18);
}

/* =========================
   ACTIVE
   ========================= */
.btn-tabulator-bar button:active,
#btn-recargar:active,
#clear-filters:active,
#toggle-columns-btn:active,
#btn-seleccionados:active,
#btn-ejecutar-store-html:active,
#clear-sort:active{
    transform: translateY(0);
    box-shadow: inset 0 2px 4px rgba(0,0,0,.08);
}

/* =========================
   CONTENEDOR GENERAL
   ========================= */
.tabulator-wrapper{
    width:100%;
    max-width:100%;
    overflow:hidden;
    border:1px solid #d7dde5;
    border-radius:12px;
    background:#ffffff;
    box-shadow:0 4px 14px rgba(15, 23, 42, .06);
}

/* =========================
   TABLA BASE
   ========================= */
#example-table{
    border:none !important;
    background:#ffffff;
    font-family: "Segoe UI", Tahoma, Arial, sans-serif;
    font-size:13px;
    color:#1f2937;
}

#example-table .tabulator{
    border:none !important;
    background:#ffffff;
}

/* =========================
   HEADER PRINCIPAL
   ========================= */
#example-table .tabulator-header{
    background:#f8fafc;
    border-bottom:1px solid #d7dde5;
}

#example-table .tabulator-col{
    background:#f8fafc !important;
    border-right:1px solid #e5e7eb !important;
    border-bottom:1px solid #d7dde5 !important;
    padding:0 !important;
}

#example-table .tabulator-col:last-child{
    border-right:none !important;
}

#example-table .tabulator-col .tabulator-col-content{
    padding:10px 10px 8px 10px !important;
}

#example-table .tabulator-col-title{
    font-size:12px;
    font-weight:700;
    letter-spacing:.08em;
    text-transform:uppercase;
    color:#64748b;
}

/* =========================
   FILA DE FILTROS
   ========================= */
#example-table .tabulator-header-filter{
    padding:6px 8px 10px 8px !important;
    background:#f8fafc !important;
}

#example-table .tabulator-header-filter input,
#example-table .tabulator-header-filter select{
    width:100%;
    height:32px;
    border:1px solid #cfd8e3;
    border-radius:8px;
    background:#ffffff;
    box-sizing:border-box;
    padding:6px 10px;
    font-size:12px;
    color:#334155;
    outline:none;
    transition:border-color .15s ease, box-shadow .15s ease;
}

#example-table .tabulator-header-filter input:focus,
#example-table .tabulator-header-filter select:focus{
    border-color:#60a5fa;
    box-shadow:0 0 0 3px rgba(96,165,250,.16);
}

#example-table .tabulator-header-filter svg{
    opacity:.8;
}

/* =========================
   BODY / FILAS / CELDAS
   ========================= */
#example-table .tabulator-tableholder{
    background:#ffffff;
}

#example-table .tabulator-row{
    background:#ffffff;
    border-bottom:1px solid #edf1f5;
    transition:background-color .12s ease;
}

#example-table .tabulator-row:nth-child(even){
    background:#fcfdff;
}

#example-table .tabulator-row:hover{
    background:#f8fbff !important;
}

#example-table .tabulator-cell{
    border-right:1px solid #edf1f5 !important;
    padding:10px 12px !important;
    vertical-align:middle;
    white-space:nowrap;
    overflow:hidden;
    text-overflow:ellipsis;
}

#example-table .tabulator-cell:last-child{
    border-right:none !important;
}

/* =========================
   COLUMNAS CONGELADAS
   Quita efecto duro de división
   ========================= */
#example-table .tabulator-col.tabulator-frozen,
#example-table .tabulator-cell.tabulator-frozen,
#example-table .tabulator-frozen-left,
#example-table .tabulator-frozen-right{
    border-right:1px solid #edf1f5 !important;
    border-left:none !important;
    box-shadow:none !important;
}

/* =========================
   SCROLLBARS
   ========================= */
#example-table .tabulator-tableholder::-webkit-scrollbar,
#example-table .tabulator-footer::-webkit-scrollbar{
    height:10px;
    width:10px;
}

#example-table .tabulator-tableholder::-webkit-scrollbar-track,
#example-table .tabulator-footer::-webkit-scrollbar-track{
    background:#eef2f7;
    border-radius:8px;
}

#example-table .tabulator-tableholder::-webkit-scrollbar-thumb,
#example-table .tabulator-footer::-webkit-scrollbar-thumb{
    background:#b9c5d3;
    border-radius:8px;
}

#example-table .tabulator-tableholder::-webkit-scrollbar-thumb:hover,
#example-table .tabulator-footer::-webkit-scrollbar-thumb:hover{
    background:#94a3b8;
}

/* =========================
   CHECKBOX DE SELECCIÓN
   ========================= */
#example-table input[type="checkbox"]{
    width:16px;
    height:16px;
    accent-color:#2563eb;
    cursor:pointer;
}

/* =========================
   BOTÓN EXPANDIR ADDONS
   ========================= */
.btn-expand-row{
    width:28px;
    height:28px;
    border:1px solid #cbd5e1;
    border-radius:8px;
    background:linear-gradient(180deg,#ffffff 0%, #f1f5f9 100%);
    color:#1e3a8a;
    font-size:18px;
    font-weight:700;
    line-height:1;
    cursor:pointer;
    box-shadow:0 1px 2px rgba(0,0,0,.04);
    transition:all .15s ease;
}

.btn-expand-row:hover{
    background:#eff6ff;
    border-color:#93c5fd;
    transform:translateY(-1px);
}

/* =========================
   BADGE DE ADDONS
   ========================= */
.addon-badge{
    display:inline-flex;
    align-items:center;
    justify-content:center;
    min-width:20px;
    height:20px;
    padding:0 6px;
    margin-left:6px;
    border-radius:999px;
    background:#f97316;
    color:#ffffff;
    font-size:11px;
    font-weight:700;
    line-height:1;
    box-shadow:0 1px 3px rgba(249,115,22,.35);
}

.no-addon-mark{
    color:#94a3b8;
    font-size:18px;
}

/* =========================
   ESTADOS CORRECTO / INCORRECTO / PENDIENTE
   ========================= */
.estado-ok,
.estado-error,
.estado-alerta{
    display:inline-flex;
    align-items:center;
    justify-content:center;
    min-width:110px;
    padding:5px 10px;
    border-radius:999px;
    font-size:11px;
    font-weight:700;
    letter-spacing:.02em;
    white-space:nowrap;
}

.estado-ok{
    background:#ecfdf3;
    color:#15803d;
    border:1px solid #bbf7d0;
}

.estado-error{
    background:#fef2f2;
    color:#b91c1c;
    border:1px solid #fecaca;
}

.estado-alerta{
    background:#fff7ed;
    color:#c2410c;
    border:1px solid #fed7aa;
}

/* =========================
   CHECK BONITO PARA sin_incidencia
   ========================= */
.chk-bonito{
    display:inline-flex;
    align-items:center;
    justify-content:center;
    width:22px;
    height:22px;
    border-radius:6px;
    font-weight:700;
    font-size:14px;
    line-height:1;
    transition:all .15s ease;
    box-sizing:border-box;
}

#example-table .tabulator-cell:hover .chk-bonito{
    transform:scale(1.08);
}

/* =========================
   PAGINACIÓN
   ========================= */
#example-table .tabulator-footer{
    background:#f8fafc;
    border-top:1px solid #d7dde5;
    padding:8px 10px;
}

#example-table .tabulator-page{
    border:1px solid #cfd8e3 !important;
    background:#ffffff !important;
    color:#334155 !important;
    border-radius:8px !important;
    min-width:34px;
    height:32px;
    line-height:30px;
    margin:0 3px !important;
    font-size:12px;
    font-weight:600;
}

#example-table .tabulator-page.active{
    background:#2563eb !important;
    border-color:#2563eb !important;
    color:#ffffff !important;
}

#example-table .tabulator-page:hover{
    background:#eff6ff !important;
    border-color:#93c5fd !important;
}

/* =========================
   FILA DETALLE ADDONS
   ========================= */
.detail-row-holder{
    padding:16px 18px 18px 64px;
    background:linear-gradient(180deg,#fff7ed 0%, #ffffff 100%);
    border-bottom:1px solid #e5e7eb;
}

.detail-row-title{
    font-size:14px;
    font-weight:700;
    margin-bottom:4px;
    color:#c2410c;
}

.detail-row-subtitle{
    font-size:12px;
    color:#64748b;
    margin-bottom:12px;
}

/* =========================
   CELDA EN EDICIÓN
   ========================= */
#example-table .tabulator-cell.tabulator-editing{
    outline:none !important;
    box-shadow:inset 0 0 0 2px rgba(37,99,235,.18);
    background:#ffffff !important;
}

#example-table .tabulator-cell.tabulator-editing input,
#example-table .tabulator-cell.tabulator-editing select{
    border:1px solid #93c5fd !important;
    border-radius:8px !important;
    box-shadow:0 0 0 3px rgba(96,165,250,.14);
    padding:6px 8px !important;
    height:32px !important;
    box-sizing:border-box;
}

/* =========================
   TEXTO DESTACADO
   ========================= */
#example-table .cliente-destacado{
    font-weight:700;
    color:#0f172a;
}

/* =========================
   RESPONSIVE VISUAL
   ========================= */
@media (max-width: 1200px){
    #example-table{
        font-size:12px;
    }

    #example-table .tabulator-cell{
        padding:9px 10px !important;
    }

    #example-table .tabulator-col-title{
        font-size:11px;
    }
}

</style>


<div class="tabulator-wrapper">

    </div>
        <div class="btn-tabulator-bar">
        <button id="btn-recargar">Recargar</button>
        <button id="clear-filters">Limpiar</button>
        <button id="toggle-columns-btn">Columnas</button>
        <button id="btn-seleccionados">Seleccionados</button>
    </div>

    <div id="example-table"></div>
</div>';
